const aboutLabels: Record<string, Record<AboutItemLabelKey | 'about', string>> = {
  'zh-CN': {
    discord: 'Discord',
    xiaohongshu: '小红书',
    wechatOfficial: '公众号',
    github: 'GitHub',
    website: '官网',
    about: '关于',
  },
  en: {
    discord: 'Discord',
    xiaohongshu: 'Xiaohongshu',
    wechatOfficial: 'WeChat',
    github: 'GitHub',
    website: 'Website',
    about: 'About',
  },
  ja: {
    discord: 'Discord',
    xiaohongshu: '小紅書',
    wechatOfficial: 'WeChat',
    github: 'GitHub',
    website: '公式サイト',
    about: '概要',
  },
  ko: {
    discord: 'Discord',
    xiaohongshu: '샤오홍슈',
    wechatOfficial: 'WeChat',
    github: 'GitHub',
    website: '공식 사이트',
    about: '정보',
  },
};

const getAboutLabel = (locale: string, key: AboutItemLabelKey | 'about') => aboutLabels[locale]?.[key] ?? aboutLabels.en[key];

export default function LocalAboutPanel() {
  const locale = useLocale();
  const aboutPanelRef = useRef<HTMLDivElement>(null);
  const [isAboutPanelOpen, setIsAboutPanelOpen] = useState(false);

  useEffect(() => {
    if (!isAboutPanelOpen) return;
    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === 'Escape') setIsAboutPanelOpen(false);
    };
    const handlePointerDown = (event: MouseEvent) => {
      if (!aboutPanelRef.current?.contains(event.target as Node)) setIsAboutPanelOpen(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('mousedown', handlePointerDown);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('mousedown', handlePointerDown);
    };
  }, [isAboutPanelOpen]);

  return (
    <div ref={aboutPanelRef} className="relative mt-auto px-4">
      {isAboutPanelOpen && (
        <div
          role="dialog"
          aria-label={`OpenFMV ${getAboutLabel(locale, 'about')}`}
          className="absolute bottom-8 left-4 w-[236px] rounded-openfmv-panel border border-white/10 bg-[#202020]/96 p-2 text-openfmv-text shadow-[0_22px_80px_rgba(0,0,0,0.44)] backdrop-blur-2xl"
        >
          <div className="px-3 pb-2 pt-2">
            <div className="text-sm font-semibold text-white">OpenFMV</div>
            <div className="mt-1 text-xs font-medium text-openfmv-muted">{getAboutLabel(locale, 'about')}</div>
          </div>
          <div className="grid grid-cols-2 gap-1 border-t border-white/[0.08] pt-2">
            {aboutItems.map((item) => {
              const Icon = item.icon;
              const label = getAboutLabel(locale, item.labelKey);
              return (
                <div key={item.labelKey} className="flex h-[58px] flex-col items-center justify-center gap-1.5 rounded-openfmv-control px-2 text-center text-[11px] font-semibold leading-4 text-openfmv-sub transition hover:bg-white/[0.055] hover:text-white">
                  {item.path ? (
                    <svg aria-hidden="true" viewBox="0 0 24 24" className={`h-[18px] w-[18px] ${item.colorClassName}`} fill="currentColor">
                      <path d={item.path} />
                    </svg>
                  ) : Icon ? (
                    <Icon size={18} className={item.colorClassName} />
                  ) : (
                    null
                  )}
                  <span className="max-w-full truncate">{label}</span>
                </div>
              );
            })}
          </div>
        </div>
      )}
      <button
        type="button"
        aria-expanded={isAboutPanelOpen}
        aria-haspopup="dialog"
        onClick={() => setIsAboutPanelOpen((value) => !value)}
        className="inline-flex h-7 items-center gap-2 text-xs font-semibold text-openfmv-muted transition hover:text-white"
      >
        <span>OpenFMV</span>
        <span className="text-white/[0.18]">·</span>
        <span>{getAboutLabel(locale, 'about')}</span>
      </button>
    </div>
  );
}
